146	/// The “real” environment variables type.
147	/// Instead of just calling `var_os` from within the options module,
148	/// the method of looking up environment variables has to be passed in.
149	struct LiveVars;
150	impl Vars for LiveVars {
151	    fn get(&self, name: &'static str) -> Option<OsString> {
152	        env::var_os(name)
