156	/// Create a Git cache populated with the arguments that are going to be
157	/// listed before they’re actually listed, if the options demand it.
158	fn git_options(options: &Options, args: &[&OsStr]) -> Option<GitCache> {
159	    if options.should_scan_for_git() {
160	        Some(args.iter().map(PathBuf::from).collect())
161	    } else {
162	        None
163	    }
164	}
