171	#[cfg(feature = "git")]
172	fn get_files_in_dir(paths: &mut Vec<PathBuf>, path: PathBuf) {
173	    let temp_paths = if path.is_dir() {
174	        match path.read_dir() {
175	            Err(_) => {
176	                vec![path]
177	            }
178	            Ok(d) => d
179	                .filter_map(|entry| entry.ok().map(|e| e.path()))
180	                .collect::<Vec<PathBuf>>(),
181	        }
182	    } else {
183	        vec![path]
184	    };
185	    paths.extend(temp_paths);
186	}
187	
188	#[cfg(feature = "git")]
189	fn git_repos(options: &Options, args: &[&OsStr]) -> bool {
190	    let option_enabled = match options.view.mode {
191	        Mode::Details(details::Options {
192	            table: Some(ref table),
193	            ..
194	        })
195	        | Mode::GridDetails(grid_details::Options {
196	            details:
197	                details::Options {
198	                    table: Some(ref table),
199	                    ..
200	                },
201	            ..
202	        }) => table.columns.subdir_git_repos || table.columns.subdir_git_repos_no_stat,
