222	impl Exa<'_> {
223	    /// # Errors
224	    ///
225	    /// Will return `Err` if printing to stderr fails.
226	    pub fn run(mut self) -> io::Result<i32> {
227	        debug!("Running with options: {:#?}", self.options);
228	
229	        let mut files = Vec::new();
230	        let mut dirs = Vec::new();
231	        let mut exit_status = 0;
232	
233	        for file_path in &self.input_paths {
234	            let f = File::from_args(
235	                PathBuf::from(file_path),
236	                None,
237	                None,
238	                self.options.view.deref_links,
239	                self.options.view.total_size,
240	                None,
241	            );
242	
243	            // We don't know whether this file exists, so we have to try to get
244	            // the metadata to verify.
245	            if let Err(e) = f.metadata() {
246	                exit_status = 2;
247	                writeln!(io::stderr(), "{file_path:?}: {e}")?;
248	                continue;
249	            }
250	
251	            if f.points_to_directory() && !self.options.dir_action.treat_dirs_as_files() {
252	                trace!("matching on new Dir");
253	                dirs.push(f.to_dir());
254	            } else {
255	                files.push(f);
256	            }
257	        }
258	
259	        // We want to print a directory’s name before we list it, *except* in
260	        // the case where it’s the only directory, *except* if there are any
261	        // files to print as well. (It’s a double negative)
262	
263	        let no_files = files.is_empty();
264	        let is_only_dir = dirs.len() == 1 && no_files;
265	
266	        self.options.filter.filter_argument_files(&mut files);
267	        self.print_files(None, files)?;
268	
269	        self.print_dirs(dirs, no_files, is_only_dir, exit_status)
270	    }
271	
272	    fn print_dirs(
273	        &mut self,
274	        dir_files: Vec<Dir>,
275	        mut first: bool,
276	        is_only_dir: bool,
277	        exit_status: i32,
278	    ) -> io::Result<i32> {
279	        let View {
280	            file_style: file_name::Options { quote_style, .. },
281	            ..
282	        } = self.options.view;
283	
284	        let mut denied_dirs = vec![];
285	
286	        for mut dir in dir_files {
287	            let dir = match dir.read() {
288	                Ok(dir) => dir,
289	                Err(e) => {
290	                    if e.kind() == ErrorKind::PermissionDenied {
291	                        eprintln!(
292	                            "Permission denied: {} - code: {}",
293	                            dir.path.display(),
294	                            exits::PERMISSION_DENIED
295	                        );
296	                        denied_dirs.push(dir.path);
297	                        continue;
298	                    }
299	
300	                    eprintln!("{}: {}", dir.path.display(), e);
301	                    continue;
302	                }
303	            };
304	
305	            // Put a gap between directories, or between the list of files and
306	            // the first directory.
307	            if first {
308	                first = false;
309	            } else {
310	                writeln!(&mut self.writer)?;
311	            }
312	
313	            if !is_only_dir {
314	                let mut bits = Vec::new();
315	                escape(
316	                    dir.path.display().to_string(),
317	                    &mut bits,
318	                    Style::default(),
319	                    Style::default(),
320	                    quote_style,
321	                );
322	                writeln!(&mut self.writer, "{}:", ANSIStrings(&bits))?;
323	            }
324	
325	            let mut children = Vec::new();
326	            let git_ignore = self.options.filter.git_ignore == GitIgnore::CheckAndIgnore;
327	            for file in dir.files(
328	                self.options.filter.dot_filter,
329	                self.git.as_ref(),
330	                git_ignore,
331	                self.options.view.deref_links,
332	                self.options.view.total_size,
333	            ) {
334	                children.push(file);
335	            }
336	            let recursing = self.options.dir_action.recurse_options().is_some();
337	            self.options
338	                .filter
339	                .filter_child_files(recursing, &mut children);
340	            self.options.filter.sort_files(&mut children);
341	
342	            if let Some(recurse_opts) = self.options.dir_action.recurse_options() {
343	                let depth = dir
344	                    .path
345	                    .components()
346	                    .filter(|&c| c != Component::CurDir)
347	                    .count()
348	                    + 1;
349	                let follow_links = self.options.view.follow_links;
350	                if !recurse_opts.tree && !recurse_opts.is_too_deep(depth) {
351	                    let child_dirs = children
352	                        .iter()
353	                        .filter(|f| {
354	                            (if follow_links {
355	                                f.points_to_directory()
356	                            } else {
357	                                f.is_directory()
358	                            }) && !f.is_all_all
359	                        })
360	                        .map(fs::File::to_dir)
361	                        .collect::<Vec<Dir>>();
362	
363	                    self.print_files(Some(dir), children)?;
364	                    match self.print_dirs(child_dirs, false, false, exit_status) {
365	                        Ok(_) => (),
366	                        Err(e) => return Err(e),
367	                    }
368	                    continue;
369	                }
370	            }
371	
372	            self.print_files(Some(dir), children)?;
373	        }
374	
375	        if !denied_dirs.is_empty() {
376	            eprintln!(
377	                "\nSkipped {} directories due to permission denied: ",
378	                denied_dirs.len()
379	            );
380	            for path in denied_dirs {
381	                eprintln!("  {}", path.display());
382	            }
383	        }
384	
385	        Ok(exit_status)
386	    }
387	
388	    /// Prints the list of files using whichever view is selected.
389	    fn print_files(&mut self, dir: Option<&Dir>, mut files: Vec<File<'_>>) -> io::Result<()> {
390	        if files.is_empty() {
391	            return Ok(());
392	        }
393	        let recursing = self.options.dir_action.recurse_options().is_some();
394	        let only_files = self.options.filter.flags.contains(&OnlyFiles);
395	        if recursing && only_files {
396	            files = files
397	                .into_iter()
398	                .filter(|f| !f.is_directory())
399	                .collect::<Vec<_>>();
400	        }
401	        let theme = &self.theme;
402	        let View {
403	            ref mode,
404	            ref file_style,
405	            ..
406	        } = self.options.view;
407	
408	        match (mode, self.console_width) {
409	            (Mode::Grid(opts), Some(console_width)) => {
410	                let filter = &self.options.filter;
411	                let r = grid::Render {
412	                    files,
413	                    theme,
414	                    file_style,
415	                    opts,
416	                    console_width,
417	                    filter,
418	                };
419	                r.render(&mut self.writer)
420	            }
421	
422	            (Mode::Grid(opts), None) => {
423	                let filter = &self.options.filter;
424	                let r = grid::Render {
425	                    files,
426	                    theme,
427	                    file_style,
428	                    opts,
429	                    console_width: 80,
430	                    filter,
431	                };
432	                r.render(&mut self.writer)
433	            }
434	
435	            (Mode::Lines, _) => {
436	                let filter = &self.options.filter;
437	                let r = lines::Render {
438	                    files,
439	                    theme,
440	                    file_style,
441	                    filter,
442	                };
443	                r.render(&mut self.writer)
444	            }
445	
446	            (Mode::Details(opts), _) => {
447	                let filter = &self.options.filter;
448	                let recurse = self.options.dir_action.recurse_options();
449	
450	                let git_ignoring = self.options.filter.git_ignore == GitIgnore::CheckAndIgnore;
451	                let git = self.git.as_ref();
452	                let git_repos = self.git_repos;
453	                let r = details::Render {
454	                    dir,
455	                    files,
456	                    theme,
457	                    file_style,
458	                    opts,
459	                    recurse,
460	                    filter,
461	                    git_ignoring,
462	                    git,
463	                    git_repos,
464	                };
465	                r.render(&mut self.writer)
466	            }
467	
468	            (Mode::GridDetails(opts), Some(console_width)) => {
469	                let details = &opts.details;
470	                let row_threshold = opts.row_threshold;
471	
472	                let filter = &self.options.filter;
473	                let git_ignoring = self.options.filter.git_ignore == GitIgnore::CheckAndIgnore;
474	                let git = self.git.as_ref();
475	                let git_repos = self.git_repos;
476	
477	                let r = grid_details::Render {
478	                    dir,
479	                    files,
480	                    theme,
481	                    file_style,
482	                    details,
483	                    filter,
484	                    row_threshold,
485	                    git_ignoring,
486	                    git,
487	                    console_width,
488	                    git_repos,
489	                };
490	                r.render(&mut self.writer)
491	            }
492	
493	            (Mode::GridDetails(opts), None) => {
494	                let opts = &opts.to_details_options();
495	                let filter = &self.options.filter;
496	                let recurse = self.options.dir_action.recurse_options();
497	                let git_ignoring = self.options.filter.git_ignore == GitIgnore::CheckAndIgnore;
498	                let git = self.git.as_ref();
499	                let git_repos = self.git_repos;
500	
501	                let r = details::Render {
502	                    dir,
503	                    files,
504	                    theme,
505	                    file_style,
506	                    opts,
507	                    recurse,
508	                    filter,
509	                    git_ignoring,
510	                    git,
511	                    git_repos,
512	                };
513	                r.render(&mut self.writer)
514	            }
515	        }
516	    }
517	}
518	
519	mod exits {
520	
521	    /// Exit code for when exa runs OK.
522	    pub const SUCCESS: i32 = 0;
523	
524	    /// Exit code for when there was at least one I/O error during execution.
525	    pub const RUNTIME_ERROR: i32 = 1;
526	
527	    /// Exit code for when the command-line options are invalid.
528	    pub const OPTIONS_ERROR: i32 = 3;
529	
530	    /// Exit code for missing file permissions
531	    pub const PERMISSION_DENIED: i32 = 13;
532	}
